code = """import json
import re

file_path = locals()['var_function-call-9392313590174593508']
with open(file_path, 'r') as f:
    articles = json.load(f)

sports_keywords = set([
    "football", "baseball", "basketball", "soccer", "tennis", "golf", "hockey", 
    "olympic", "olympics", "paralympic", "medal", "medals", "athlete", "athletes", 
    "championship", "championships", "champion", "champions", "tournament", "tournaments", 
    "stadium", "arena", "nba", "nfl", "mlb", "nhl", "fifa", "uefa",
    "wimbledon", "athens", "game", "games", "match", "matches", "team", "teams", 
    "score", "scores", "win", "won", "winner", "winners", "loss", "lost", "loser", 
    "coach", "coaches", "player", "players", "roster", "squad",
    "touchdown", "quarterback", "goalkeeper", "homerun", "slam", "dunk",
    "serena", "venus", "williams", "roddick", "agassi", "federer", "phelps", "thorpe",
    "armstrong", "schumacher", "red", "sox", "yankees", "lakers", "pistons", "spurs"
])

# Negative keywords to avoid false positives (e.g. "team" in business)
negative_keywords = set([
    "stock", "stocks", "market", "economy", "investment", "fund", "profit", 
    "revenue", "sales", "software", "microsoft", "google", "intel", "linux", 
    "iraq", "military", "war", "president", "bush", "kerry", "election", 
    "senate", "congress", "un", "nuclear", "bomb", "terror", "police", "court" 
    # court is tricky, but "in court" vs "on court". Tokenizer separates.
])
# "court" in tennis is common. "court" in law is common.
# I'll risk "court" being negative? No, Serena article has "court".
# I'll remove "court" from negative.
negative_keywords.remove("court")

candidates = []

for art in articles:
    # simple tokenization: split by non-alphanumeric
    text = (art.get('title', '') + " " + art.get('description', '')).lower()
    tokens = set(re.split(r'[^a-z0-9]+', text))
    
    # Score
    score = 0
    # Check sports keywords
    hits = tokens.intersection(sports_keywords)
    score += len(hits)
    
    # Check negative
    neg_hits = tokens.intersection(negative_keywords)
    score -= len(neg_hits) * 2
    
    if score > 0:
        candidates.append({
            'title': art['title'],
            'description': art['description'],
            'len': len(art['description']),
            'score': score,
            'hits': list(hits)
        })

# Sort by len desc
candidates.sort(key=lambda x: x['len'], reverse=True)

print("__RESULT__:")
print(json.dumps({'top_candidates': candidates[:5]}))"""

